diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..05bed8288e63 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,28 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0), X, 0), C --> fcmp oeq X, C
+      // If X is ordered (not NaN), select returns X and we compare X == C.
+      // If X is NaN (unordered), select returns 0 and we compare 0 == C,
+      // which is false (assuming C != 0). For NaN, fcmp oeq X, C is also false.
+      // Therefore, both give the same result.
+      if (Pred == FCmpInst::FCMP_OEQ) {
+        SelectInst *SI = cast<SelectInst>(LHSI);
+        Value *Cond = SI->getCondition();
+        if (auto *FCond = dyn_cast<FCmpInst>(Cond)) {
+          if (FCond->getPredicate() == FCmpInst::FCMP_ORD &&
+              FCond->hasOneUse()) {
+            Value *FCondOp0 = FCond->getOperand(0);
+            Value *FCondOp1 = FCond->getOperand(1);
+            Value *TV = SI->getTrueValue();
+            Value *FV = SI->getFalseValue();
+            if (TV == FCondOp0 && match(FCondOp1, m_AnyZeroFP()) &&
+                match(FV, m_AnyZeroFP())) {
+              return replaceOperand(I, 0, TV);
+            }
+          }
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

